using System.ComponentModel;
using System.Text;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — HttpClient and ILogger are constructor-injected by the DI container.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all items from the API.")]
    public async Task<string> ListItems(
        [Description("Maximum number of items to return (1-100).")] int limit = 20,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing up to {Limit} items", limit);

        var response = await httpClient.GetAsync($"/items?limit={limit}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool, Description("Get a single item by its unique identifier.")]
    public async Task<string> GetItem(
        [Description("The unique identifier of the item.")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching item {Id}", id);

        var response = await httpClient.GetAsync($"/items/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new item with the given name and description.")]
    public async Task<string> CreateItem(
        [Description("Name of the item to create.")] string name,
        [Description("Optional description for the item.")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item {Name}", name);

        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        var content = new StringContent(payload, Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/items", content, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(Destructive = true, Idempotent = true),
     Description("Delete an item by its unique identifier.")]
    public async Task<string> DeleteItem(
        [Description("The unique identifier of the item to delete.")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Deleting item {Id}", id);

        var response = await httpClient.DeleteAsync($"/items/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();

        return $"Item {id} deleted successfully.";
    }
}

